     7→ * @see specs/005-api.md Section 5.3
     8→ */
     9→
    10→import { Hono } from 'hono';
    11→import {
    12→  success,
    13→  paginatedSuccess,
    14→  error,
    15→  parsePaginationQuery,
    16→  ErrorCodes,
    17→  type AppVariables,
    18→} from '../types';
