/**
 * Error Handler Middleware
 *
 * Centralized error handling for all API errors.
 * Maps MMS error classes to appropriate HTTP status codes and response formats.
 *
 * @see specs/005-api.md for error response format
 */

import type { Context, ErrorHandler, NotFoundHandler } from 'hono';
import { HTTPException } from 'hono/http-exception';
import { error, ErrorCodes, type AppVariables } from '../types';
import { logger } from '../../lib/logging/logger';
import {
  MmsError,
  ValidationError,
  NotFoundError,
  ConflictError,
  AuthenticationError,
  AuthorizationError,
  MaximoLockError,
  ComplianceWindowError,
  TrackConflictError,
  MaterialConstraintError,
  ServiceDemandViolationError,
  DatabaseError,
  ExternalServiceError,
  ServiceUnavailableError,
} from '../../lib/errors';

/**
 * Map MMS error to HTTP status code
 */
function getStatusCode(err: Error): number {
  if (err instanceof HTTPException) {
    return err.status;
  }

  if (err instanceof ValidationError) return 400;
  if (err instanceof AuthenticationError) return 401;
  if (err instanceof AuthorizationError) return 403;
  if (err instanceof NotFoundError) return 404;
  if (err instanceof ConflictError) return 409;
  if (err instanceof MaximoLockError) return 409;
  if (err instanceof ComplianceWindowError) return 422;
  if (err instanceof TrackConflictError) return 422;
  if (err instanceof MaterialConstraintError) return 422;
  if (err instanceof ServiceDemandViolationError) return 422;
  if (err instanceof ServiceUnavailableError) return 503;
  if (err instanceof DatabaseError) return 503;
  if (err instanceof ExternalServiceError) return 502;
  if (err instanceof MmsError) return err.statusCode || 500;

  return 500;
}

/**
 * Map MMS error to error code
 */
function getErrorCode(err: Error): string {
  if (err instanceof HTTPException) {
    if (err.status === 401) return ErrorCodes.UNAUTHORIZED;
    if (err.status === 403) return ErrorCodes.FORBIDDEN;
    if (err.status === 404) return ErrorCodes.NOT_FOUND;
    if (err.status === 429) return ErrorCodes.RATE_LIMITED;
    return ErrorCodes.INTERNAL_ERROR;
  }

  if (err instanceof ValidationError) return ErrorCodes.VALIDATION_ERROR;
  if (err instanceof AuthenticationError) return ErrorCodes.UNAUTHORIZED;
  if (err instanceof AuthorizationError) return ErrorCodes.FORBIDDEN;
  if (err instanceof NotFoundError) return ErrorCodes.NOT_FOUND;
  if (err instanceof ConflictError) return ErrorCodes.CONFLICT;
  if (err instanceof MaximoLockError) return ErrorCodes.MAXIMO_LOCK;
  if (err instanceof ComplianceWindowError) return ErrorCodes.OUTSIDE_WINDOW;
  if (err instanceof TrackConflictError) return ErrorCodes.TRACK_CONFLICT;
  if (err instanceof MaterialConstraintError) return ErrorCodes.MATERIAL_BLOCK;
  if (err instanceof ServiceDemandViolationError) return ErrorCodes.SERVICE_DEMAND_VIOLATION;
  if (err instanceof ServiceUnavailableError) return ErrorCodes.SERVICE_UNAVAILABLE;
  if (err instanceof DatabaseError) return ErrorCodes.DATABASE_ERROR;
  if (err instanceof ExternalServiceError) return ErrorCodes.EXTERNAL_SERVICE_ERROR;
  if (err instanceof MmsError) return err.code;

  return ErrorCodes.INTERNAL_ERROR;
}

/**
 * Get error details for response
 */
function getErrorDetails(err: Error): unknown {
  if (err instanceof ValidationError) {
    return {
      field: err.field,
      errors: err.errors,
    };
  }

  if (err instanceof MmsError && err.context) {
    return err.context;
  }

  return undefined;
}

/**
 * Create error handler for Hono app
 */
export function createErrorHandler(): ErrorHandler<{ Variables: AppVariables }> {
  return (err: Error, c: Context<{ Variables: AppVariables }>) => {
    const requestId = c.get('requestId') || 'unknown';
    const statusCode = getStatusCode(err);
    const errorCode = getErrorCode(err);
    const details = getErrorDetails(err);

    // Log error with context
    const logData = {
      requestId,
      method: c.req.method,
      path: c.req.path,
      statusCode,
      errorCode,
      error: err.message,
      stack: statusCode >= 500 ? err.stack : undefined,
    };

    if (statusCode >= 500) {
      logger.error(logData, 'Request failed with server error');
    } else if (statusCode >= 400) {
      logger.warn(logData, 'Request failed with client error');
    }

    return c.json(error(errorCode, err.message, requestId, details), statusCode as 400);
  };
}

/**
 * Not found handler for undefined routes
 */
export function notFoundHandler(): NotFoundHandler<{ Variables: AppVariables }> {
  return (c: Context<{ Variables: AppVariables }>) => {
    const requestId = c.get('requestId') || 'unknown';
    return c.json(
      error(
        ErrorCodes.NOT_FOUND,
        `Route not found: ${c.req.method} ${c.req.path}`,
        requestId
      ),
      404
    );
  };
}

